using Quartz;
using Quartz.Spi;

static IReadOnlyList<DateTimeOffset> ComputeDaily24(DateTime startDateTime, int daysAhead)
{
    DateTimeOffset startDateTimeOffset = new DateTimeOffset(startDateTime);

    TriggerBuilder triggerBuilder = TriggerBuilder.Create()
        .WithIdentity(Guid.NewGuid().ToString("N"))
        .ForJob("job")
        .StartAt(new DateTimeOffset(startDateTime.AddMinutes(1).AddSeconds(5)))
        .WithDailyTimeIntervalSchedule(scheduleBuilder =>
        {
            scheduleBuilder.OnEveryDay().WithIntervalInHours(24);
            scheduleBuilder
                .StartingDailyAt(new TimeOfDay(0, 1, 5))
                .EndingDailyAt(new TimeOfDay(23, 59, 59))
                .WithMisfireHandlingInstructionDoNothing();
        });

    return TriggerUtils.ComputeFireTimesBetween(
        (IOperableTrigger) triggerBuilder.Build(),
        null,
        startDateTimeOffset,
        startDateTimeOffset.AddDays(daysAhead));
}

static void AssertLocalSequence(string name, IReadOnlyList<DateTimeOffset> fireTimes, params DateTime[] expected)
{
    Console.WriteLine($"{name}: Count={fireTimes.Count}");
    foreach (var fireTime in fireTimes)
    {
        Console.WriteLine($"  {fireTime:o} local={fireTime.LocalDateTime:yyyy-MM-dd HH:mm:ss}");
    }

    DateTime[] actual = fireTimes.Select(x => x.LocalDateTime).ToArray();
    if (!actual.SequenceEqual(expected))
    {
        throw new Exception($"{name} mismatch. Expected [{string.Join(", ", expected.Select(x => x.ToString("s")))}], actual [{string.Join(", ", actual.Select(x => x.ToString("s")))}]");
    }
}

Console.WriteLine($"Local zone: {TimeZoneInfo.Local.Id} Base={TimeZoneInfo.Local.BaseUtcOffset}");

AssertLocalSequence(
    "fall-back 24-hour daily interval",
    ComputeDaily24(new DateTime(2020, 10, 25), 3),
    new DateTime(2020, 10, 25, 0, 1, 5),
    new DateTime(2020, 10, 26, 0, 1, 5),
    new DateTime(2020, 10, 27, 0, 1, 5));

AssertLocalSequence(
    "spring-forward 24-hour daily interval",
    ComputeDaily24(new DateTime(2020, 3, 29), 3),
    new DateTime(2020, 3, 29, 0, 1, 5),
    new DateTime(2020, 3, 30, 0, 1, 5),
    new DateTime(2020, 3, 31, 0, 1, 5));

var hourlyTrigger = (IOperableTrigger) TriggerBuilder.Create()
    .WithIdentity("hourly")
    .ForJob("job")
    .StartAt(new DateTimeOffset(new DateTime(2020, 10, 25)))
    .WithDailyTimeIntervalSchedule(scheduleBuilder => scheduleBuilder
        .OnEveryDay()
        .StartingDailyAt(new TimeOfDay(0, 0, 0))
        .EndingDailyAt(new TimeOfDay(4, 0, 0))
        .WithIntervalInHours(1))
    .Build();

AssertLocalSequence(
    "fall-back hourly wall-clock interval",
    TriggerUtils.ComputeFireTimesBetween(
        hourlyTrigger,
        null,
        new DateTimeOffset(new DateTime(2020, 10, 25)),
        new DateTimeOffset(new DateTime(2020, 10, 25, 5, 0, 0))),
    new DateTime(2020, 10, 25, 0, 0, 0),
    new DateTime(2020, 10, 25, 1, 0, 0),
    new DateTime(2020, 10, 25, 2, 0, 0),
    new DateTime(2020, 10, 25, 3, 0, 0),
    new DateTime(2020, 10, 25, 4, 0, 0));
