    /// <summary>
    /// Set the previous time at which the <see cref="IDailyTimeIntervalTrigger" /> fired.
    /// </summary>
    /// <remarks>
    /// This method should not be invoked by client code.
    /// </remarks>
    /// <param name="previousFireTimeUtc"></param>
