private DateTimeOffset CreateTimeZoneAdjustedDateTimeOffset(DateTime dateTime, DateTimeOffset? earliestTime = null)
{
    DateTimeOffset fireTime = new DateTimeOffset(dateTime, TimeZoneUtil.GetUtcOffset(dateTime, TimeZone));
    if (earliestTime is null || fireTime >= earliestTime.Value || !TimeZone.IsAmbiguousTime(dateTime))
    {
        return fireTime;
    }

    DateTimeOffset? nextAmbiguousFireTime = null;
    foreach (TimeSpan offset in TimeZone.GetAmbiguousTimeOffsets(dateTime))
    {
        DateTimeOffset candidate = new DateTimeOffset(dateTime, offset);
        if (candidate >= earliestTime.Value && (nextAmbiguousFireTime is null || candidate < nextAmbiguousFireTime.Value))
        {
            nextAmbiguousFireTime = candidate;
        }
    }

    return nextAmbiguousFireTime ?? fireTime;
}

