static void AssertSequence(string name, IReadOnlyList<DateTimeOffset> fireTimes, params DateTime[] expectedLocal)
{
    Console.WriteLine($"{name}: {fireTimes.Count}");
    foreach (var fireTime in fireTimes) Console.WriteLine($"  {fireTime:o} local={fireTime.LocalDateTime:yyyy-MM-dd HH:mm:ss}");
